using System.Text.Json;
using System.Text.Json.Nodes;

// in-process ?몄텧 ?듭뀡. PendingTransitionId媛 ?덉쑝硫?state-only 1??硫댁젣瑜??곸슜?쒕떎.
internal record ReconciliationOptions(
    string WorkstatePath,
    string ApplierLogPath,
    string? PendingTransitionId = null
);

// 媛쒕퀎 log ??ぉ ?뚯떛 寃곌낵.
internal record LogEntry(
    string TransitionId,
    string Result,
    int ExitCode,
    string At,
    int SchemaVersion,
    string? TransitionContractSha256
);

// lookupSuccess 諛섑솚媛???06C-1 idempotency ?먯젙??
